function byKey(arr, keyFn){const m=new Map();arr.forEach(x=>m.set(keyFn(x),x));return m}
function upsertBy(arr, item, keyFn, mergeFn){const key=keyFn(item);const idx=arr.findIndex(x=>keyFn(x)===key);if(idx>=0){arr[idx]=mergeFn?mergeFn(arr[idx],item):{...arr[idx],...item};return false}else{arr.push(item);return true}}
function mergeVipImportData(silent=false){if(!Array.isArray(state.vips))state.vips=[];if(!Array.isArray(state.docs))state.docs=[];if(!Array.isArray(state.vipOperations))state.vipOperations=[];if(!Array.isArray(state.vipLeads))state.vipLeads=[];if(!Array.isArray(state.deals))state.deals=[];let added={vips:0,docs:0,ops:0,leads:0,deals:0};VIP_IMPORT_DATA.vips.forEach(v=>{const inserted=upsertBy(state.vips,v,x=>x.client,(old,item)=>({...old,...item,amo:old.amo||item.amo,folder:old.folder||item.folder,risk:item.risk||old.risk}));if(inserted)added.vips++});VIP_IMPORT_DATA.vipOperations.forEach(op=>{const inserted=upsertBy(state.vipOperations,op,x=>x.id);if(inserted)added.ops++});VIP_IMPORT_DATA.docs.forEach(doc=>{const key=x=>(x.sourceId||'')+'|'+(x.client||'')+'|'+(x.type||'')+'|'+(x.name||'')+'|'+(x.link||'');const inserted=upsertBy(state.docs,doc,key,(old,item)=>({...old,...item,link:old.link||item.link,status:item.status||old.status,priority:item.priority||old.priority}));if(inserted)added.docs++});VIP_IMPORT_DATA.vipLeads.forEach(lead=>{const inserted=upsertBy(state.vipLeads,lead,x=>x.id);if(inserted)added.leads++;const deal={id:'hunter_'+lead.id,sourceLeadId:lead.id,source:'hunter_vip_sheet',client:lead.title,amo:'',service:lead.activityDescription||'VIP от хантера',amount:Number(lead.depositedToHunter||0),stage:'В работе',invoiceDate:'',payDate:'',include:'no',nextAction:lead.nextAction,nextDate:'',comment:`Реквизиты: ${lead.requisites||'—'} · Остаток: ${money(lead.balance||0)} · Месяц: ${lead.workMonth||'—'}`};const dealInserted=upsertBy(state.deals,deal,x=>x.sourceLeadId||x.id,(old,item)=>({...old,...item,stage:old.stage||item.stage,include:'no'}));if(dealInserted)added.deals++});if(!state.selectedVip&&state.vips.length)state.selectedVip=state.vips[0].client;state.vipImportVersion=VIP_IMPORT_VERSION;save();if(!silent){render();alert(`VIP-база обновлена: ${VIP_IMPORT_DATA.summary.vipCount} клиентов, ${VIP_IMPORT_DATA.summary.operationCount} операций, ${VIP_IMPORT_DATA.summary.docCount} документов, ${VIP_IMPORT_DATA.summary.leadCount} задела от хантера.`)}}
