function autoArchive(d){if(!state.archive.some(a=>a.sourceId===d.id)){state.archive.unshift({id:Date.now(),sourceId:d.id,client:d.client,amount:d.amount,reason:'Отказ',canReturn:'yes',returnDate:'',hook:'Вернуться с новым предложением',amo:d.amo,comment:d.comment||''})}}
