function renderDocs(){const body=$('docsBody');body.innerHTML='';$('emptyDocs').style.display=state.docs.length?'none':'block';state.docs.forEach((d,i)=>{const tr=document.createElement('tr');tr.innerHTML=`<td>${esc(d.client)}</td><td>${esc(d.type)}</td><td>${esc(d.name)}</td><td>${d.link?`<a class="mini-btn link" target="_blank" href="${esc(d.link)}">Открыть</a>`:'—'}</td><td><span class="pill ${d.status==='Готово'?'pay':d.status==='Проблема'?'over':'wait'}">${d.status}</span></td><td>${esc(d.date||'')}</td><td>${esc((d.priority?d.priority+' · ':'')+(d.comment||''))}</td><td><button class="mini-btn del" data-del-doc="${i}">Удалить</button></td>`;body.appendChild(tr)});document.querySelectorAll('[data-del-doc]').forEach(b=>b.onclick=()=>{state.docs.splice(+b.dataset.delDoc,1);render()})}
function archiveTemplate(a){
  const name=a.client||'';
  const hook=a.hook||'вернуться с более точным предложением';
  const reason=a.reason||'';
  if(reason==='Дорого')return `Здравствуйте! Возвращаюсь к нашему прошлому обсуждению. Понимаю, что тогда вопрос упирался в бюджет. Сейчас могу предложить более аккуратный вариант: ${hook}. Если актуально, коротко покажу, как можно решить задачу без лишних затрат.`;
  if(reason==='Думает')return `Здравствуйте! Возвращаюсь к нашему диалогу по задаче. Вы тогда брали паузу подумать. Сейчас хочу коротко напомнить суть предложения и предложить следующий шаг: ${hook}. Удобно вернуться к обсуждению?`;
  if(reason==='Молчит')return `Здравствуйте! Понимаю, что могли быть другие приоритеты. Возвращаюсь аккуратно: по вашей задаче всё ещё можно сделать ${hook}. Если вопрос уже неактуален — подскажите, пожалуйста, чтобы я не отвлекал(а).`;
  if(reason==='Нет бюджета')return `Здравствуйте! Возвращаюсь к вопросу бюджета. Сейчас можно рассмотреть более мягкий вариант входа: ${hook}. Могу коротко расписать, как это будет выглядеть по сумме и этапам.`;
  if(reason==='Выбрал конкурента')return `Здравствуйте! Хотел(а) уточнить, как у вас продвигается решение задачи. Если появятся вопросы, сложности или потребуется альтернативный взгляд, мы можем вернуться с вариантом: ${hook}.`;
  return `Здравствуйте! Возвращаюсь к нашему прошлому обсуждению. Сейчас есть повод вернуться к задаче: ${hook}. Если актуально, могу коротко напомнить варианты и следующий шаг.`;
}
