function renderArchive(){
  const total=state.archive.length, moneySum=state.archive.reduce((s,a)=>s+Number(a.amount||0),0);
  const returns=state.archive.filter(a=>a.canReturn==='yes');
  const week=returns.filter(a=>!a.returnDate||daysDiff(a.returnDate)<=7).length;
  $('archiveTotal').textContent=total;$('archiveMoney').textContent=money(moneySum);$('archiveReturn').textContent=returns.length;$('archiveWeek').textContent=week;
  const list=$('returnList');list.innerHTML='';$('returnEmpty').style.display=returns.length?'none':'block';
  returns.slice().sort((a,b)=>{
    const da=a.returnDate?daysDiff(a.returnDate):999, db=b.returnDate?daysDiff(b.returnDate):999;
    if(da!==db)return da-db;return Number(b.amount||0)-Number(a.amount||0);
  }).slice(0,10).forEach(a=>{
    const i=state.archive.indexOf(a);
    const div=document.createElement('div');div.className='return-card';
    div.innerHTML=`<div class="return-main"><h3>${esc(a.client)}</h3><p>${esc(a.reason)} · ${esc(a.hook||'чем вернуть не указано')}</p><p>Дата возврата: ${esc(a.returnDate||'не указана')}</p></div><div class="return-side"><b>${money(a.amount)}</b>${a.amo?`<a class="mini-btn link" target="_blank" href="${esc(a.amo)}">AMO</a>`:''}<button class="copy-btn" data-arch-msg="${i}">Текст</button><button class="return-btn" data-return-deal="${i}">В задел</button></div>`;
    list.appendChild(div);
  });
  document.querySelectorAll('[data-arch-msg]').forEach(b=>b.onclick=()=>selectArchiveMessage(+b.dataset.archMsg));
  document.querySelectorAll('[data-return-deal]').forEach(b=>b.onclick=()=>returnToDeal(+b.dataset.returnDeal));
  const body=$('archiveBody');body.innerHTML='';$('emptyArchive').style.display=state.archive.length?'none':'block';
  state.archive.forEach((a,i)=>{const tr=document.createElement('tr');tr.innerHTML=`<td>${esc(a.client)}</td><td><b>${money(a.amount)}</b></td><td>${esc(a.reason)}</td><td>${a.canReturn==='yes'?'Да':'Нет'}</td><td>${esc(a.returnDate||'')}</td><td>${esc(a.hook||'')}</td><td>${a.amo?`<a class="mini-btn link" target="_blank" href="${esc(a.amo)}">AMO</a>`:'—'}</td><td>${esc(a.comment||'')}</td><td><button class="mini-btn del" data-del-arch="${i}">Удалить</button></td>`;body.appendChild(tr)});
  document.querySelectorAll('[data-del-arch]').forEach(b=>b.onclick=()=>{state.archive.splice(+b.dataset.delArch,1);render()});
  if(state.selectedArchive!==undefined&&state.archive[state.selectedArchive])$('returnMessage').textContent=archiveTemplate(state.archive[state.selectedArchive]);
}
function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function fillSelects(){$('dealStage').innerHTML=dealStages.map(s=>`<option>${s}</option>`).join('')}
function hydrateDates(){['dealInvoiceDate','vipControlDate','docDate','touchDate'].forEach(id=>$(id).value=today())}
function hydratePlans(){const p=plan();['ordinaryPlan','highPlan','superPlan','bonus','ordinaryRate','highRate'].forEach(id=>$(id).value=p[id])}
function bindPlans(){['ordinaryPlan','highPlan','superPlan','bonus','ordinaryRate','highRate'].forEach(id=>$(id).addEventListener('input',()=>{plan()[id]=Number($(id).value);render()}))}
function openDrawer(mode){$('drawer').classList.add('open');$('drawerBg').classList.add('open');if(mode)showTab(mode+'Form')}function closeDrawer(){$('drawer').classList.remove('open');$('drawerBg').classList.remove('open')}
function showTab(id){['dealForm','vipForm','docForm','archiveForm','touchForm'].forEach(x=>$(x).classList.toggle('hidden',x!==id));document.querySelectorAll('[data-tab]').forEach(b=>b.className='btn '+(b.dataset.tab===id?'primary':'secondary'))}
function addDeal(){const client=$('dealClient').value.trim(),amount=Number($('dealAmount').value);if(!client||!amount){alert('Заполни клиента и сумму задела.');return}state.deals.unshift({id:Date.now(),client,amo:$('dealAmo').value.trim(),service:$('dealService').value.trim(),amount,stage:$('dealStage').value,invoiceDate:$('dealInvoiceDate').value,payDate:$('dealStage').value==='Оплачено'&&!$('dealPayDate').value?today():$('dealPayDate').value,include:$('dealInclude').value,nextAction:$('dealNextAction').value.trim(),nextDate:$('dealNextDate').value,comment:$('dealComment').value.trim()});['dealClient','dealAmo','dealService','dealAmount','dealPayDate','dealNextAction','dealNextDate','dealComment'].forEach(id=>$(id).value='');closeDrawer();render()}
function addVip(){const client=$('vipClient').value.trim();if(!client){alert('Заполни клиента.');return}state.vips.unshift({client,amo:$('vipAmo').value.trim(),folder:$('vipFolder').value.trim(),deposit:Number($('vipDeposit').value||0),nextAction:$('vipNextAction').value.trim(),controlDate:$('vipControlDate').value,risk:$('vipRisk').value,terms:$('vipTerms').value.trim(),comment:$('vipComment').value.trim()});['vipClient','vipAmo','vipFolder','vipDeposit','vipNextAction','vipTerms','vipComment'].forEach(id=>$(id).value='');closeDrawer();render()}
function addDoc(){const client=$('docClient').value.trim();if(!client){alert('Заполни клиента.');return}state.docs.unshift({client,type:$('docType').value,name:$('docName').value.trim(),link:$('docLink').value.trim(),status:$('docStatus').value,priority:$('docPriority').value,date:$('docDate').value,comment:$('docComment').value.trim()});['docClient','docName','docLink','docComment'].forEach(id=>$(id).value='');closeDrawer();render()}
function addArchive(){const client=$('archClient').value.trim();if(!client){alert('Заполни клиента.');return}state.archive.unshift({id:Date.now(),client,amount:Number($('archAmount').value||0),reason:$('archReason').value,canReturn:$('archReturn').value,returnDate:$('archReturnDate').value,hook:$('archHook').value.trim(),amo:$('archAmo').value.trim(),comment:$('archComment').value.trim()});['archClient','archAmount','archReturnDate','archHook','archAmo','archComment'].forEach(id=>$(id).value='');closeDrawer();render()}
function loadDemo(){const m=state.currentMonth;state.plans[m]={...defaults};state.deals=[{id:1,client:'ООО Вектор',amo:'https://example.com',service:'Товарный знак',amount:420000,stage:'Оплачено',invoiceDate:`${m}-02`,payDate:`${m}-04`,include:'yes',nextAction:'Получить акт',nextDate:`${m}-05`,comment:'оплата прошла'},{id:2,client:'ГК Альфа',amo:'https://example.com',service:'Депозит',amount:520000,stage:'Счёт выставлен',invoiceDate:`${m}-15`,payDate:'',include:'yes',nextAction:'Напомнить про оплату',nextDate:`${m}-18`,comment:'ждём оплату'},{id:3,client:'VIP Бренд',amo:'https://example.com',service:'Пополнение',amount:300000,stage:'Ждём оплату',invoiceDate:`${m}-18`,payDate:'',include:'yes',nextAction:'Запросить платёжку',nextDate:`${m}-20`,comment:'обещали оплатить'},{id:4,client:'ООО Линия',amo:'https://example.com',service:'Договор',amount:190000,stage:'Просрочено',invoiceDate:`${m}-10`,payDate:'',include:'yes',nextAction:'Позвонить',nextDate:`${m}-12`,comment:'напомнить'},{id:5,client:'ИП Орлова',amo:'',service:'Консультация',amount:280000,stage:'Оффер',invoiceDate:'',payDate:'',include:'yes',nextAction:'Отправить аргументы',nextDate:`${m}-23`,comment:'готовим предложение'}];state.vips=[{client:'VIP Бренд',amo:'https://example.com',folder:'https://drive.google.com',deposit:650000,nextAction:'Запросить платёжку',controlDate:`${m}-20`,risk:'Высокий',terms:'Особые условия оплаты',comment:'ключевой клиент'},{client:'ГК Альфа',amo:'https://example.com',folder:'https://drive.google.com',deposit:250000,nextAction:'Проверить документы',controlDate:`${m}-28`,risk:'Средний',terms:'Работа по депозиту',comment:''}];state.docs=[{client:'VIP Бренд',type:'Платёжка',name:'Платёжное поручение июнь',link:'https://drive.google.com',status:'Нужно получить',priority:'Критично',date:`${m}-20`,comment:'ждём от клиента'},{client:'VIP Бренд',type:'Счёт',name:'Счёт на пополнение',link:'https://drive.google.com',status:'Готово',priority:'Важная',date:`${m}-18`,comment:'выставлен клиенту'},{client:'VIP Бренд',type:'Договор',name:'Основной договор',link:'https://drive.google.com',status:'На проверке',priority:'Важная',date:`${m}-16`,comment:'проверить подпись'},{client:'ГК Альфа',type:'Договор',name:'Договор 2026',link:'https://drive.google.com',status:'Готово',priority:'Обычная',date:`${m}-10`,comment:''}];state.selectedVip='VIP Бренд';state.touchpoints=[{id:201,date:`${m}-19`,client:'ГК Альфа',type:'Сообщение',result:'Обещал оплатить',amount:520000,nextDate:`${m}-21`,nextAction:'Напомнить про оплату',amo:'https://example.com',comment:'обещали оплатить после согласования'},{id:202,date:`${m}-18`,client:'VIP Бренд',type:'Звонок',result:'Попросил документы',amount:300000,nextDate:`${m}-20`,nextAction:'Отправить платёжку и договор',amo:'https://example.com',comment:'ждут документы'},{id:203,date:`${m}-17`,client:'ООО Линия',type:'Сообщение',result:'Молчит',amount:190000,nextDate:`${m}-19`,nextAction:'Позвонить',amo:'https://example.com',comment:'нет ответа'}];state.archive=[{id:101,client:'ООО Стартап',amount:180000,reason:'Думает',canReturn:'yes',returnDate:`${m}-25`,hook:'вернуться с новым оффером и рассрочкой',amo:'https://example.com',comment:'вернуться с новым оффером'},{id:102,client:'ИП Север',amount:260000,reason:'Дорого',canReturn:'yes',returnDate:`${m}-21`,hook:'предложить облегчённый пакет',amo:'https://example.com',comment:'нужен мягкий заход'},{id:103,client:'ООО Тест',amount:120000,reason:'Молчит',canReturn:'yes',returnDate:'',hook:'коротко уточнить актуальность',amo:'',comment:'нет ответа'}];render()}
function exportData(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='crmanager-v7-data.json';a.click();URL.revokeObjectURL(a.href)}
function importData(file){const r=new FileReader();r.onload=()=>{try{state={...defaultState,...JSON.parse(r.result)};if(!state.doneFocus)state.doneFocus={};render()}catch(e){alert('Не удалось импортировать файл')}};r.readAsText(file)}
document.addEventListener('DOMContentLoaded',()=>{fillSelects();hydrateDates();hydratePlans();bindPlans();document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>setView(b.dataset.view));document.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>openDrawer(b.dataset.mode));document.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>showTab(b.dataset.tab));document.querySelectorAll('[data-focus-filter]').forEach(b=>b.onclick=()=>{state.focusFilter=b.dataset.focusFilter;renderFocusPage();save()});$('closeDrawer').onclick=closeDrawer;$('drawerBg').onclick=closeDrawer;$('addDeal').onclick=addDeal;$('addVip').onclick=addVip;$('addDoc').onclick=addDoc;$('addArchive').onclick=addArchive;$('addTouch').onclick=addTouch;$('demoBtn').onclick=loadDemo;$('exportBtn').onclick=exportData;$('clearBtn').onclick=()=>{if(confirm('Очистить данные?')){state={...defaultState,currentMonth:state.currentMonth,theme:state.theme};render()}};$('copyReturnMessage').onclick=()=>{navigator.clipboard&&navigator.clipboard.writeText($('returnMessage').textContent||'')};$('refreshTemplate').onclick=renderGeneratedTemplate;$('copyGeneratedTemplate').onclick=()=>copyToClipboard($('templateOutput').textContent||'');['tplClient','tplContext','tplTone','tplScenario'].forEach(id=>$(id).addEventListener('input',renderGeneratedTemplate));$('themeBtn').onclick=()=>{state.theme=state.theme==='dark'?'light':'dark';render()};$('prevMonth').onclick=()=>{state.currentMonth=addMonths(state.currentMonth,-1);render()};$('nextMonth').onclick=()=>{state.currentMonth=addMonths(state.currentMonth,1);render()};$('todayMonth').onclick=()=>{state.currentMonth=new Date().toISOString().slice(0,7);render()};$('importFile').onchange=e=>{if(e.target.files[0])importData(e.target.files[0])};$('importVipBaseBtn').onclick=()=>mergeVipImportData(false);if(state.vipImportVersion!==VIP_IMPORT_VERSION)mergeVipImportData(true);render();if(new URLSearchParams(location.search).get('demo')==='1')loadDemo()});
